files.main.tf:
terraform {
  required_providers {
    hafen = {
      source = "kubequest/hafen"
    }
  }
}

# Ein neues Ost-Plateau für Port Kubernia
resource "hafen_plateau" "ost" {
  name   = "ost-erweiterung"
  breite = 12
}

# Zwei Server für den wachsenden Cluster
resource "hafen_server" "worker" {
  count   = 2
  name    = "worker-${count.index + 3}"
  groesse = "mittel"
}
